<?php
if ( ! defined( 'ABSPATH' ) ) { exit; } class TCT_Backup { const CRON_HOOK = 'tct_daily_backup'; const MAX_BACKUPS = 30; const BACKUP_DIR_NAME = 'tct-backups'; private static $backup_dir = null; private static $tables = array( 'tct_domains', 'tct_roles', 'tct_goals', 'tct_completions', 'tct_ledger', 'tct_sleep_cycles', ); private static $user_meta_keys = array( 'tct_todoist_access_token', 'tct_todoist_connected_at', 'tct_todoist_oauth_state', 'tct_todoist_oauth_redirect_to', 'tct_last_sync_at_utc', 'tct_last_sync_status', 'tct_labels_cache', 'tct_labels_cache_at_utc', 'tct_points_started_at_utc', 'tct_reward_active', 'tct_reward_hof', ); private static $option_keys = array( 'tct_todoist_client_id', 'tct_todoist_client_secret', 'tct_sync_interval_minutes', 'tct_sync_horizon_days', 'tct_cron_user_offset', 'tct_db_version', 'tct_settings_schema_version', 'tct_experimental_features_enabled', 'tct_timezone', 'tct_progress_images_enabled', ); public static function init() { add_action( self::CRON_HOOK, array( __CLASS__, 'run_daily_backup' ) ); add_action( 'wp_ajax_tct_backup_create', array( __CLASS__, 'ajax_create_backup' ) ); add_action( 'wp_ajax_tct_backup_restore', array( __CLASS__, 'ajax_restore_backup' ) ); add_action( 'wp_ajax_tct_backup_delete', array( __CLASS__, 'ajax_delete_backup' ) ); add_action( 'wp_ajax_tct_backup_list', array( __CLASS__, 'ajax_list_backups' ) ); add_action( 'wp_ajax_tct_backup_download', array( __CLASS__, 'ajax_download_backup' ) ); } public static function schedule_daily() { if ( ! wp_next_scheduled( self::CRON_HOOK ) ) { wp_schedule_event( time() + 60, 'daily', self::CRON_HOOK ); } } public static function unschedule() { $ts = wp_next_scheduled( self::CRON_HOOK ); while ( $ts ) { wp_unschedule_event( $ts, self::CRON_HOOK ); $ts = wp_next_scheduled( self::CRON_HOOK ); } } public static function run_daily_backup() { $error = ''; self::create_backup( 'daily', $error ); if ( '' !== $error ) { error_log( 'TCT Backup (daily): ' . $error ); } self::prune_old_backups(); } private static function get_backup_dir() { if ( null !== self::$backup_dir ) { return self::$backup_dir; } $upload_dir = wp_upload_dir(); $dir = trailingslashit( $upload_dir['basedir'] ) . self::BACKUP_DIR_NAME; if ( ! file_exists( $dir ) ) { wp_mkdir_p( $dir ); } $htaccess = $dir . '/.htaccess'; if ( ! file_exists( $htaccess ) ) { @file_put_contents( $htaccess, "Order Deny,Allow\nDeny from all\n" ); } $index = $dir . '/index.php'; if ( ! file_exists( $index ) ) { @file_put_contents( $index, '<?php // Silence is golden.' ); } self::$backup_dir = $dir; return $dir; } public static function create_backup( $type = 'manual', &$error = '' ) { global $wpdb; $dir = self::get_backup_dir(); if ( ! is_dir( $dir ) || ! is_writable( $dir ) ) { $error = 'Backup directory is not writable: ' . $dir; return null; } $backup = array( 'version' => 1, 'plugin_ver' => defined( 'TCT_VERSION' ) ? TCT_VERSION : 'unknown', 'db_version' => (int) get_option( 'tct_db_version', 0 ), 'type' => $type, 'created_at' => gmdate( 'Y-m-d H:i:s' ), 'site_url' => get_site_url(), 'tables' => array(), 'user_meta' => array(), 'options' => array(), ); foreach ( self::$tables as $table_suffix ) { $table = $wpdb->prefix . $table_suffix; $exists = $wpdb->get_var( $wpdb->prepare( 'SELECT COUNT(*) FROM information_schema.tables WHERE table_schema = %s AND table_name = %s', DB_NAME, $table ) ); if ( ! $exists ) { $backup['tables'][ $table_suffix ] = array(); continue; } $rows = $wpdb->get_results( "SELECT * FROM `{$table}`", ARRAY_A ); $backup['tables'][ $table_suffix ] = is_array( $rows ) ? $rows : array(); } $user_ids = array(); foreach ( self::$user_meta_keys as $meta_key ) { $uids = $wpdb->get_col( $wpdb->prepare( "SELECT DISTINCT user_id FROM {$wpdb->usermeta} WHERE meta_key = %s", $meta_key ) ); if ( is_array( $uids ) ) { foreach ( $uids as $uid ) { $user_ids[ (int) $uid ] = true; } } } foreach ( array_keys( $user_ids ) as $uid ) { $meta = array(); foreach ( self::$user_meta_keys as $meta_key ) { $val = get_user_meta( $uid, $meta_key, true ); if ( '' !== $val && false !== $val ) { $meta[ $meta_key ] = $val; } } if ( ! empty( $meta ) ) { $backup['user_meta'][ (string) $uid ] = $meta; } } foreach ( self::$option_keys as $opt_key ) { $val = get_option( $opt_key, null ); if ( null !== $val ) { $backup['options'][ $opt_key ] = $val; } } $date_str = gmdate( 'Y-m-d_His' ); $filename = 'tct-backup-' . $type . '-' . $date_str . '.json'; $filepath = trailingslashit( $dir ) . $filename; $json = wp_json_encode( $backup, JSON_PRETTY_PRINT | JSON_UNESCAPED_UNICODE ); if ( false === $json ) { $error = 'Failed to encode backup data as JSON.'; return null; } $written = @file_put_contents( $filepath, $json ); if ( false === $written ) { $error = 'Failed to write backup file: ' . $filepath; return null; } return $filename; } public static function restore_backup( $filename, &$error = '' ) { global $wpdb; $filename = sanitize_file_name( $filename ); $filepath = trailingslashit( self::get_backup_dir() ) . $filename; if ( ! file_exists( $filepath ) ) { $error = 'Backup file not found.'; return false; } $json = @file_get_contents( $filepath ); if ( false === $json || '' === trim( $json ) ) { $error = 'Could not read backup file.'; return false; } $backup = json_decode( $json, true ); if ( ! is_array( $backup ) || empty( $backup['tables'] ) ) { $error = 'Invalid backup file format.'; return false; } $pre_error = ''; self::create_backup( 'pre-restore', $pre_error ); if ( class_exists( 'TCT_DB' ) && is_callable( array( 'TCT_DB', 'create_tables' ) ) ) { TCT_DB::create_tables(); } $wpdb->query( 'SET autocommit = 0' ); $wpdb->query( 'START TRANSACTION' ); $success = true; foreach ( self::$tables as $table_suffix ) { $table = $wpdb->prefix . $table_suffix; if ( ! isset( $backup['tables'][ $table_suffix ] ) ) { continue; } $rows = $backup['tables'][ $table_suffix ]; $del = $wpdb->query( "DELETE FROM `{$table}`" ); if ( false === $del ) { $error = 'Failed to clear table ' . $table_suffix . ': ' . $wpdb->last_error; $success = false; break; } if ( empty( $rows ) ) { continue; } foreach ( $rows as $row ) { if ( ! is_array( $row ) || empty( $row ) ) { continue; } $result = $wpdb->insert( $table, $row ); if ( false === $result ) { $error = 'Failed to insert row into ' . $table_suffix . ': ' . $wpdb->last_error; $success = false; break 2; } } } if ( ! $success ) { $wpdb->query( 'ROLLBACK' ); $wpdb->query( 'SET autocommit = 1' ); return false; } $wpdb->query( 'COMMIT' ); $wpdb->query( 'SET autocommit = 1' ); if ( isset( $backup['user_meta'] ) && is_array( $backup['user_meta'] ) ) { foreach ( $backup['user_meta'] as $uid_str => $meta_arr ) { $uid = (int) $uid_str; if ( $uid <= 0 || ! is_array( $meta_arr ) ) { continue; } if ( ! get_userdata( $uid ) ) { continue; } foreach ( $meta_arr as $meta_key => $meta_val ) { if ( ! in_array( $meta_key, self::$user_meta_keys, true ) ) { continue; } update_user_meta( $uid, $meta_key, $meta_val ); } } } if ( isset( $backup['options'] ) && is_array( $backup['options'] ) ) { foreach ( $backup['options'] as $opt_key => $opt_val ) { if ( ! in_array( $opt_key, self::$option_keys, true ) ) { continue; } update_option( $opt_key, $opt_val ); } } return true; } public static function list_backups() { $dir = self::get_backup_dir(); $files = glob( trailingslashit( $dir ) . 'tct-backup-*.json' ); if ( ! is_array( $files ) ) { return array(); } $backups = array(); foreach ( $files as $filepath ) { $filename = basename( $filepath ); $size = @filesize( $filepath ); $fh = @fopen( $filepath, 'r' ); $type = 'unknown'; $created_at = ''; if ( $fh ) { $header = fread( $fh, 2048 ); fclose( $fh ); if ( preg_match( '/"type"\s*:\s*"([^"]+)"/', $header, $m ) ) { $type = $m[1]; } if ( preg_match( '/"created_at"\s*:\s*"([^"]+)"/', $header, $m ) ) { $created_at = $m[1]; } } if ( '' === $created_at ) { $created_at = gmdate( 'Y-m-d H:i:s', filemtime( $filepath ) ); } $backups[] = array( 'filename' => $filename, 'type' => $type, 'size' => $size, 'size_human' => size_format( $size, 1 ), 'created_at' => $created_at, ); } usort( $backups, function ( $a, $b ) { return strcmp( $b['created_at'], $a['created_at'] ); } ); return $backups; } public static function prune_old_backups() { $all = self::list_backups(); $daily = array(); foreach ( $all as $b ) { if ( 'daily' === $b['type'] ) { $daily[] = $b; } } if ( count( $daily ) <= self::MAX_BACKUPS ) { return; } $to_remove = array_slice( $daily, self::MAX_BACKUPS ); $dir = self::get_backup_dir(); foreach ( $to_remove as $b ) { $path = trailingslashit( $dir ) . $b['filename']; if ( file_exists( $path ) ) { @unlink( $path ); } } } public static function ajax_create_backup() { TCT_Utils::enforce_ajax_nonce( 'tct_backup', 'nonce' ); if ( ! current_user_can( 'manage_options' ) ) { TCT_Utils::send_json_error( array( 'message' => 'Permission denied.', 'code' => 'permission_denied' ), 403 ); } $error = ''; $filename = self::create_backup( 'manual', $error ); if ( null === $filename ) { TCT_Utils::send_json_error( array( 'message' => 'Backup failed: ' . $error, 'code' => 'backup_failed' ) ); } TCT_Utils::send_json_success( array( 'message' => 'Backup created successfully.', 'filename' => $filename, 'backups' => self::list_backups(), ) ); } public static function ajax_restore_backup() { TCT_Utils::enforce_ajax_nonce( 'tct_backup', 'nonce' ); if ( ! current_user_can( 'manage_options' ) ) { TCT_Utils::send_json_error( array( 'message' => 'Permission denied.', 'code' => 'permission_denied' ), 403 ); } $filename = isset( $_POST['filename'] ) ? sanitize_file_name( $_POST['filename'] ) : ''; if ( '' === $filename ) { TCT_Utils::send_json_error( array( 'message' => 'No backup file specified.', 'code' => 'missing_filename' ) ); } $error = ''; $result = self::restore_backup( $filename, $error ); if ( ! $result ) { TCT_Utils::send_json_error( array( 'message' => 'Restore failed: ' . $error, 'code' => 'restore_failed' ) ); } TCT_Utils::send_json_success( array( 'message' => 'Backup restored successfully. A pre-restore snapshot was saved automatically.', 'backups' => self::list_backups(), ) ); } public static function ajax_delete_backup() { TCT_Utils::enforce_ajax_nonce( 'tct_backup', 'nonce' ); if ( ! current_user_can( 'manage_options' ) ) { TCT_Utils::send_json_error( array( 'message' => 'Permission denied.', 'code' => 'permission_denied' ), 403 ); } $filename = isset( $_POST['filename'] ) ? sanitize_file_name( $_POST['filename'] ) : ''; if ( '' === $filename ) { TCT_Utils::send_json_error( array( 'message' => 'No backup file specified.', 'code' => 'missing_filename' ) ); } $filepath = trailingslashit( self::get_backup_dir() ) . $filename; if ( ! file_exists( $filepath ) ) { TCT_Utils::send_json_error( array( 'message' => 'Backup file not found.', 'code' => 'not_found' ) ); } @unlink( $filepath ); TCT_Utils::send_json_success( array( 'message' => 'Backup deleted.', 'backups' => self::list_backups(), ) ); } public static function ajax_list_backups() { TCT_Utils::enforce_ajax_nonce( 'tct_backup', 'nonce' ); if ( ! current_user_can( 'manage_options' ) ) { TCT_Utils::send_json_error( array( 'message' => 'Permission denied.', 'code' => 'permission_denied' ), 403 ); } TCT_Utils::send_json_success( array( 'backups' => self::list_backups() ) ); } public static function ajax_download_backup() { if ( ! isset( $_GET['nonce'] ) || ! wp_verify_nonce( sanitize_text_field( $_GET['nonce'] ), 'tct_backup' ) ) { wp_die( 'Invalid nonce.', 403 ); } if ( ! current_user_can( 'manage_options' ) ) { wp_die( 'Permission denied.', 403 ); } $filename = isset( $_GET['filename'] ) ? sanitize_file_name( $_GET['filename'] ) : ''; if ( '' === $filename ) { wp_die( 'No file specified.', 400 ); } $filepath = trailingslashit( self::get_backup_dir() ) . $filename; if ( ! file_exists( $filepath ) ) { wp_die( 'File not found.', 404 ); } header( 'Content-Type: application/json' ); header( 'Content-Disposition: attachment; filename="' . $filename . '"' ); header( 'Content-Length: ' . filesize( $filepath ) ); readfile( $filepath ); exit; } public static function render_settings_section() { if ( ! current_user_can( 'manage_options' ) ) { return ''; } $next_scheduled = wp_next_scheduled( self::CRON_HOOK ); $next_label = $next_scheduled ? date_i18n( 'M j, Y g:i a', $next_scheduled + ( get_option( 'gmt_offset', 0 ) * HOUR_IN_SECONDS ) ) : 'Not scheduled'; $html = ''; $html .= '<h4 class="tct-settings-heading">Backup &amp; Restore</h4>'; $html .= '<div class="tct-backup-section" data-tct-backup-section>'; $html .= '<div class="tct-backup-actions">'; $html .= '<button type="button" class="button button-primary" data-tct-backup-create>Create Backup Now</button>'; $html .= '<span class="tct-muted tct-backup-schedule-info">Daily auto-backup enabled (next: ' . esc_html( $next_label ) . '). Up to ' . self::MAX_BACKUPS . ' daily backups kept.</span>'; $html .= '</div>'; $html .= '<div class="tct-backup-list-wrap" data-tct-backup-list-wrap>'; $html .= '<div class="tct-backup-loading tct-muted" data-tct-backup-loading>Loading backups...</div>'; $html .= '<table class="tct-table tct-backup-table" data-tct-backup-table hidden="hidden">'; $html .= '<thead><tr><th>Date</th><th>Type</th><th>Size</th><th>Actions</th></tr></thead>'; $html .= '<tbody data-tct-backup-tbody></tbody>'; $html .= '</table>'; $html .= '<p class="tct-muted" data-tct-backup-empty hidden="hidden">No backups found.</p>'; $html .= '</div>'; $html .= '</div>'; return $html; } } 
